%[text] ## 实验结果展示
%[text] 可运行此代码，查看论文相关的结果图表
%[text] 1\.四种方法下阻塞率随服务到达率的变化情况
%[text] 源数据：c.输出/论文数据.xlsx中的阻塞率sheet

% ====== 0) 环境初始化 ======
currentDir = pwd;
addpath(genpath(fullfile(currentDir, 'a.输入')));
addpath(genpath(fullfile(currentDir, 'b.常用函数')));

%% 1. 阻塞率 vs 服务到达率
% 读取数据
dataPath = fullfile(currentDir, 'c.输出', '论文数据.xlsx');
raw = readtable(dataPath, 'Sheet', '阻塞率', 'VariableNamingRule', 'preserve');

% 筛选 Arrival Rate >= 40 的数据
mask        = raw.("Arrival Rate") >= 40;
arrivalRate = raw.("Arrival Rate")(mask);
rda         = raw.("RDA")(mask);
nif         = raw.("NIF")(mask);
stb         = raw.("STB")(mask);
rsa         = raw.("RSA")(mask);

% ---- 图形参数（单栏期刊：3.5英寸；双栏：7.2英寸）----
figW     = 3.5;   % 宽度，英寸
figH     = 2.8;   % 高度，英寸
fontSize = 8;     % pt，符合大多数期刊字号要求
fontName = 'Times New Roman';

fig1 = figure('Name', 'Blocking Rate vs Arrival Rate', 'Color', 'w', ... %[output:3b314586]
    'Units', 'inches', 'Position', [1, 1, figW, figH]); %[output:3b314586]
hold on; %[output:3b314586]

% 标记稀疏化：每隔 nStep 个点显示一次标记符号
nStep = 10;
nPts  = numel(arrivalRate);
mIdx  = 1 : nStep : nPts;

h1 = plot(arrivalRate, rda, '-o', ... %[output:3b314586]
    'LineWidth', 1.0, 'MarkerSize', 4, ... %[output:3b314586]
    'Color', [0.00 0.45 0.74], 'MarkerFaceColor', [0.00 0.45 0.74], ... %[output:3b314586]
    'MarkerIndices', mIdx, 'DisplayName', 'RDA'); %[output:3b314586]
h2 = plot(arrivalRate, nif, '-s', ... %[output:3b314586]
    'LineWidth', 1.0, 'MarkerSize', 4, ... %[output:3b314586]
    'Color', [0.85 0.33 0.10], 'MarkerFaceColor', [0.85 0.33 0.10], ... %[output:3b314586]
    'MarkerIndices', mIdx, 'DisplayName', 'NIF'); %[output:3b314586]
h3 = plot(arrivalRate, stb, '-^', ... %[output:3b314586]
    'LineWidth', 1.0, 'MarkerSize', 4, ... %[output:3b314586]
    'Color', [0.93 0.69 0.13], 'MarkerFaceColor', [0.93 0.69 0.13], ... %[output:3b314586]
    'MarkerIndices', mIdx, 'DisplayName', 'STB'); %[output:3b314586]
h4 = plot(arrivalRate, rsa, '-d', ... %[output:3b314586]
    'LineWidth', 1.0, 'MarkerSize', 4, ... %[output:3b314586]
    'Color', [0.49 0.18 0.56], 'MarkerFaceColor', [0.49 0.18 0.56], ... %[output:3b314586]
    'MarkerIndices', mIdx, 'DisplayName', 'RSA'); %[output:3b314586]

hold off; %[output:3b314586]

% ---- 坐标轴与字体 ----
xlim([40, max(arrivalRate)]); %[output:3b314586]
ylim([0, 0.25]); %[output:3b314586]
xlabel('Arrival Rate',  'FontSize', fontSize, 'FontName', fontName); %[output:3b314586]
ylabel('Blocking Rate', 'FontSize', fontSize, 'FontName', fontName); %[output:3b314586]

leg = legend([h1, h2, h3, h4], 'Location', 'northwest', ... %[output:3b314586]
    'FontSize', fontSize, 'FontName', fontName); %[output:3b314586]
leg.Box = 'on'; %[output:3b314586]

grid on; %[output:3b314586]
box on; %[output:3b314586]
ax            = gca;
ax.FontSize   = fontSize; %[output:3b314586]
ax.FontName   = fontName; %[output:3b314586]
ax.LineWidth  = 0.8; %[output:3b314586]
ax.TickDir    = 'out'; %[output:3b314586]

% ---- 设置导出尺寸 ----
set(fig1, 'PaperUnits', 'inches', ...
    'PaperSize', [figW, figH], ...
    'PaperPosition', [0, 0, figW, figH]);

% ---- 保存 ----
savePath = fullfile(currentDir, 'c.输出', '6.论文图');
print(fig1, fullfile(savePath, 'Fig_BlockingRate'), '-dsvg', '-r0');   % 矢量（投稿首选） %[output:3b314586]
print(fig1, fullfile(savePath, 'Fig_BlockingRate'), '-dpng', '-r600'); % 600 dpi PNG 备用 %[output:3b314586]
fprintf('图已保存至：%s\n', savePath); %[output:1e278941]


